XEncodeParam::XEncodeParam()
{
	URL = nullptr;
	Format = eVideoFormatType::MPEG2TS;
	Program = nullptr;
	MorePrograms = nullptr;
	RealTimeMode = false;
	CopyPts = false;
}

XEncodeParam::XEncodeParam(XEncodeProgramParam^ program)
{
	URL = nullptr;
	Format = eVideoFormatType::MPEG2TS;
	Program = program;
	MorePrograms = nullptr;
	RealTimeMode = false;
	CopyPts = false;
}

int XEncodeParam::NumOfPrograms::get()
{
	int count = Program != nullptr ? 1 : 0;
	if (MorePrograms != nullptr) count += MorePrograms->Length;
	return count;
}

XEncodeProgramParam^ XEncodeParam::default::get(int index)
{
	XEncodeProgramParam^ prog = nullptr;
	if (index == 0) prog = Program;
	else if (index >= 1 && (MorePrograms != nullptr && index <= MorePrograms->Length))
	{
		prog = MorePrograms[index - 1];
	}
	return prog;
}

void XEncodeParam::AssignID(bool shareAudio, bool shareMetad)
{
	if (Program != nullptr)
	{
		VD::XEncodeParam xparam;
		CopyTo(&xparam, IntPtr(0));
		xparam.AssignID(shareAudio, shareMetad);
		for (int i = 0; i < NumOfPrograms; i++)
		{
			VD::XEncodeProgramParam* xprog = xparam.GetProgramParam(i);
			XEncodeProgramParam^ prog = this->default[i];
			prog->ProgramID = xprog->nProgramID;
			prog->viParam->StreamID = xprog->viParam.nStreamID;
