/// <summary> 동영상 형식 정의 </summary>
public enum class eVideoFormatType : System::Int32
{
	/// <summary> URL 또는 파일 확장자로 자동 결정 </summary>
	Auto	= VD::XVD_FORMAT_AUTO,
	/// <summary> MPEG-2 TS </summary>
	MPEG2TS	= VD::XVD_FORMAT_MP2TS,
	/// <summary> MPEG-4 </summary>
	MP4		= VD::XVD_FORMAT_MP4,
	/// <summary> AVI </summary>
	AVI		= VD::XVD_FORMAT_AVI,
	/// <summary> RTP MP2T </summary>
	RTP_MP2T = VD::XVD_FORMAT_RTP_MP2T,
};

/// <summary> 비디오 인코딩 코덱 </summary>
public enum class eVideoCodec : System::Int32
{
	/// <summary> MPEG-2 Video </summary>
	MPEG2VIDEO = VD::XVD_CODEC_TYPE_MPEG2VIDEO,
	/// <summary> H.264 (AVC) </summary>
	H264 = VD::XVD_CODEC_TYPE_H264,
	/// <summary> HEVC (H.265) </summary>
	HEVC = VD::XVD_CODEC_TYPE_HEVC
};

/// <summary> 오디오 샘플 형식 </summary>
public enum class eAudioSampleFormat : System::Int32
{
	/// <summary> 부호 없는 8비트 정수 </summary>
	U8		= VD::XVD_SMP_FMT_U8,
	/// <summary> 부호 있는 16비트 정수 </summary>
	S16		= VD::XVD_SMP_FMT_S16,
	/// <summary> 32비트 부동 소수점 실수 (채널별 분리) </summary>
	FLTP	= VD::XVD_SMP_FMT_FLTP
};

/// <summary> 영상 스트림 인코딩 파라미터를 설정한다. </summary>
public ref class XEncodeVideoParam
{
public:
	/// <summary> 영상 스트림 식별자. 0 이상인 정수이고, 0보다 작은 값으로 주어지면 자동으로 할당한다. </summary>
	int			StreamID;
	/// <summary> 초당 프레임 수 (FPS, Frame Per Second). </summary>
	int			viFPS;
	/// <summary> 비디오 프레임 가로 화소 수. 해상도는 반드시 2의 배수이어야 함. </summary>
	int			viFrameWidth;
	/// <summary> 비디오 프레임 세로 화소 수. 해상도는 반드시 2의 배수이어야 함. </summary>
	int			viFrameHeight;
	/// <summary> 전송률 (비트레이트). </summary>
	int			viBitRate;
	/// <summary> GOP(Group Of Picture) 크기 설정. GOP개념에 대해서는 전문서적 참조. </summary>

{
public:
	/// <summary> 출력 URL. 네트워크 스트리밍 (예, udp://123.12.12.123:1234) 또는 파일 저장 (예, D:/aa.ts). </summary>
	String^		URL;
	/// <summary> 출력 동영상 형식. </summary>
	eVideoFormatType	Format;
	/// <summary> 기본 동영상 프로그램 인코딩 파라미터. </summary>
	XEncodeProgramParam^ Program;
	/// <summary> 추가 동영상 프로그램 인코딩 파라미터. 다중 프로그램 동영상일 때 사용한다. </summary>
	cli::array<XEncodeProgramParam^>^ MorePrograms;

	/// <summary> 실제 프레임 인코딩 요청 시간 간격을 유지하는 실시간 모드 여부를 설정한다. </summary>
	bool		RealTimeMode;
	/// <summary> 트랜스코딩에서 원본 입력 동영상의 PTS를 유지하도록 설정한다. 이 때 실시간 모드는 무시된다. </summary>
	bool		CopyPts;

	/// <summary> 기본 생성자. </summary>
	XEncodeParam();
	/// <summary> XEncodeParam 클래스의 생성자로서, 동영상 프로그램 인코딩 파라미터를 설정한다. </summary>		
	/// <param name = "program"> 동영상 프로그램 인코딩 파라미터 </param>
	XEncodeParam(XEncodeProgramParam^ program);

	/// <summary> 동영상 프로그램 개수 </summary>
	property int NumOfPrograms { int get(); }
	/// <summary>
	/// 프로그램 색인에 해당하는 인코딩 파라미터를 얻는다.
	/// 색인은 기본 프로그램을 0으로 하고 순차적으로 증가하고, 범위를 벗어나면 읽을 때 널(null) 값을 반환한다.
	/// </summary>
	property XEncodeProgramParam^ default[int]
	{
		XEncodeProgramParam ^ get(int index);
	}

