bool NXImageView::GetWorldPerScreen(double% wpx, double% wpy)
{
	if(!m_pImageView)	return false;
	double dwpx,dwpy;
	bool bRes = m_pImageView->GetWorldPerScreen(dwpx,dwpy);
	wpx = dwpx;
	wpy = dwpy;
	return bRes;
}

void NXImageView::GetScreenBound(double% x1w, double% x2w, double% y1w, double% y2w)
{
	if (!m_pImageView) return;

	double dx1w, dx2w, dy1w, dy2w;
	m_pImageView->GetScreenBound(dx1w, dx2w, dy1w, dy2w);

	x1w = dx1w;
	x2w = dx2w;
	y1w = dy1w;
	y2w = dy2w;
}

bool NXImageView::SetRotationAngle(XAngle^ angle)
{
	if(!m_pImageView)	return false;
	bool result = m_pImageView->SetRotationAngle(angle->GetUnmanObj());
	RefreshScreen();
	return result;
}

XAngle^ NXImageView::GetRotationAngle()
{
	if(!m_pImageView)	return nullptr;
