{
	if (m_pSR == nullptr) return false;

	westLon = XDL::MAX_REAL64;
	southLat = XDL::MAX_REAL64;
	eastLon = XDL::MAX_REAL64;
	northLat = XDL::MAX_REAL64;

	double westLonDeg = XDL::MAX_REAL64, southLatDeg = 0.0, eastLonDeg = 0.0, northLatDeg = 0.0;
	XDL::XString xtrAreaName = "";
	if (!m_pSR->GetAreaOfUse(&westLonDeg, &southLatDeg, &eastLonDeg, &northLatDeg, xtrAreaName))
		return false;

	westLon = westLonDeg;
	southLat = southLatDeg;
	eastLon = eastLonDeg;
	northLat = northLatDeg;

	strAreaName = gcnew String(xtrAreaName.GetBuffer());
	return true;
}

