bool XCoordinateTransformation::TransformPt(double xIn, double yIn, double% xOut, double% yOut)
{
	if (m_pCT == nullptr) return false;

	double tmpx, tmpy;
	m_pCT->TransformPt(xIn, yIn, tmpx, tmpy);
	xOut = tmpx;
	yOut = tmpy;
	return true;
}

bool XCoordinateTransformation::TransformPt(double% x, double% y)
{
	if (m_pCT == nullptr) return false;
	double tmpx = x, tmpy = y;
	m_pCT->TransformPt(tmpx, tmpy);
	x = tmpx;
	y = tmpy;
	return true;
}

bool Xcc::WGP2UTM(NXDL::XAngle^ lon, NXDL::XAngle^ lat, NXDL::XVertex2d^% pos, int% Zone)
{
	double x, y;
	int izone;
	x = y = 0;
	izone = 0;

	bool bResult = CC::XCoordinateTransformation::WGP_TO_UTM(lon->deg, lat->deg, 2, x, y, izone);

	pos->x = x;
	pos->y = y;
	Zone = izone;

	return (bResult == true);
}
bool Xcc::WGP2UTM(NXDL::XAngle^ lon, NXDL::XAngle^ lat, NXDL::XVertex2d^% pos, int% Zone, String^% latitudeBand)
{
	XString str = "";
	double x, y;
	int izone;
	x = y = 0;
	izone = 0;

	bool bResult = CC::XCoordinateTransformation::WGP_TO_UTM(lon->deg, lat->deg, 2, x, y, izone, str);

	latitudeBand  = gcnew String(str.GetBuffer(0));
	pos->x = x;
	pos->y = y;
	Zone = izone;

	return (bResult == true);
}

bool Xcc::WGP2UTM(NXDL::XAngle^ lon, NXDL::XAngle^ lat, NXDL::XVertex2d^% pos, int% Zone, bool ForceApplyZone)
{
	double x, y;
	int izone;
	x = y = 0;

	if ( ForceApplyZone == true ) 
	{
		izone = Zone;
	}
	else 
	{
		izone = 0;
	}

	bool bResult = CC::XCoordinateTransformation::WGP_TO_UTM(lon->deg, lat->deg, 2, x, y, izone, ForceApplyZone);

	pos->x = x;
	pos->y = y;
	Zone = izone;

	return (bResult == true);
}

