/// D 방향을 지향하는 센서가 탑재된 N 방향 기준의 센서 자세를 나타내는 yaw, pitch, roll값을 계산한다.  <br />
/// 즉, 입력 지점에서 NED 축을 입력된 자세로 회전했을 때 센서의 시선은 N축과 일치하고,
/// 센서의 시선이 D축으로 정렬되는 자세 회전각을 계산한다.
/// </summary>
/// <param name = "ptPos"> [In] 기체/센서 위치 </param>
/// <param name = "yawPlatform"> [In] 기체 yaw 각도. </param>
/// <param name = "pitchPlatform"> [In] 기체 pitch 각도. </param>
/// <param name = "rollPlatform"> [In] 기체 roll 각도. </param>
/// <param name = "azimuthRelative"> [In] 기체를 기준으로한 센서의 방위각. </param>
/// <param name = "elevRelative"> [In] 기체를 기준으로 한 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollRelative"> [In] 센서 렌즈 축의 회전각. </param>
/// <param name = "yaw"> [Out] 최종 센서 프레임의 yaw 각도. </param>
/// <param name = "pitch"> [Out] 최종 센서 프레임의 pitch 각도. </param>
/// <param name = "roll"> [Out] 최종 센서 프레임의 roll 각도. </param>
/// <returns> 기체의 중심점에서 센서가 향하는 방향 벡터. </returns>
static XVertex3d^	CalcGlobalSensorAttitudeInPlatformUAS(XGeoPoint^ ptPos, XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthRelative, XAngle^ elevRelative, XAngle^ rollRelative, XAngle^% yaw, XAngle^% pitch, XAngle^% roll);

/// <summary>
/// UAS LS 표준에 따라 지구 타원체 상의 특정 지점에서 지구 중심으로 향하는 축과 직교하는 좌표계(NED)에서 North 시선 방향인 기체와 센서의 회전각을 입력받아서
/// 기체 자세에 상대적인 센서의 자세 회전각을 계산한다.
/// </summary>
/// <param name = "yawPlatform"> [In] 기체 yaw 각도. </param>
/// <param name = "pitchPlatform"> [In] 기체 pitch 각도. </param>
/// <param name = "rollPlatform"> [In] 기체 roll 각도. </param>
/// <param name = "azimuthSensor"> [In] NED 기준 센서의 방위각. </param>
/// <param name = "elevSensor"> [In] NED 기준 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollSensor"> [In] 센서 렌즈 축의 회전각. </param>
/// <param name = "azimuthRelative"> [Out] 기체를 기준으로 한 센서의 방위각. </param>
/// <param name = "elevRelative"> [Out] 기체를 기준으로 한 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollRelative"> [Out] 센서 렌즈 축의 회전각. </param>
static void CalcRelativeSensorAttitudeInPlatformUAS(XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthSensor, XAngle^ elevSensor, XAngle^ rollSensor, [OutAttribute] XAngle^% azimuthRelative, [OutAttribute] XAngle^% elevRelative, [OutAttribute] XAngle^% rollRelative);

/// <summary>
/// 투영 좌표계 원점의 ENU 좌표계를 기준으로 하는 카메라 회전각 omega, phi, kappa에 해당하는 센서 위치의 yaw, pitch, roll을 계산한다.
/// </summary>
/// <param name = "ptOrigin"> [In] 투영 좌표계 원점 위치. (예. Korea TM Center 127,38 / East 129,38 / West 125,38 / UTM-k 127.5,38) </param>
/// <param name = "omega"> [In] 카메라의 투영 좌표계 X축(E) 회전각. </param>
/// <param name = "phi"> [In] 카메라의 투영 좌표계 Y축(N) 회전각. </param>
/// <param name = "kappa"> [In] 카메라의 투영 좌표계 Z축(U) 회전각. </param>
/// <param name = "ptPos"> [In] 카메라 센서 위치. </param>
/// <param name = "bLookDown"> [In] 센서 회전 후 지향 방향이 하방(D)인 경우 참, 전방(N)인 경우 거짓. </param>
/// <param name = "yaw"> [Out] 센서 방위각. </param>
/// <param name = "pitch"> [Out] 센서 고각. </param>
/// <param name = "roll"> [Out] 센서 회전각. </param>
/// <returns> 센서 가시선 방향. Omega, phi, kappa 각도로 회전된 좌표축의 -Z 방향과 같다. </returns>
static XVertex3d^	OmegaPhiKappaToYawPitchRoll(XGeoPoint^ ptOrigin, XAngle^ omega, XAngle^ phi, XAngle^ kappa, XGeoPoint^ ptPos, bool bLookDown, [OutAttribute] XAngle^% yaw, [OutAttribute] XAngle^% pitch, [OutAttribute] XAngle^% roll);

/// <summary>
/// 센서 자세를 투영 좌표계 원점의 ENU 좌표계를 기준으로 하는 카메라 회전각 omega, phi, kappa로 변환한다.
/// </summary>
/// <param name = "ptPos"> [In] 카메라 센서 위치. </param>
/// <param name = "yaw"> [In] 센서 방위각. </param>
/// <param name = "pitch"> [In] 센서 고각. </param>
/// <param name = "roll"> [In] 센서 회전각. </param>
/// <param name = "bLookDown"> [In] 센서 회전 후 지향 방향이 하방(D)인 경우 참, 전방(N)인 경우 거짓. </param>
/// <param name = "ptOrigin"> [In] 투영 좌표계 원점 위치. (예. Korea TM Center 127,38 / East 129,38 / West 125,38 / UTM-k 127.5,38) </param>
/// <param name = "omega"> [Out] 카메라의 투영 좌표계 X축(E) 회전각. </param>
/// <param name = "phi"> [Out] 카메라의 투영 좌표계 Y축(N) 회전각. </param>
/// <param name = "kappa"> [Out] 카메라의 투영 좌표계 Z축(U) 회전각. </param>
/// <returns> 센서 가시선 방향. Omega, phi, kappa 각도로 회전된 좌표축의 -Z 방향과 같다. </returns>
static XVertex3d^	YawPitchRollToOmegaPhiKappa(XGeoPoint^ ptPos, XAngle^ yaw, XAngle^ pitch, XAngle^ roll, bool bLookDown, XGeoPoint^ ptOrigin, [OutAttribute] XAngle^% omega, [OutAttribute] XAngle^% phi, [OutAttribute] XAngle^% kappa);

/// <summary>
/// 로컬 좌표계에서 만든 모델을 지구 타원체 상의 특정 지점에 위치하도록 하는 자세를 구한다. <br />
/// 모델 자체의 회전이 없다면, 
/// NED 좌표축에서 N축을 모델 좌표계의 Y축, E축을 X축, D축을 -Z축과 나란히 하는 자세각을 구하여, 모델을 이 자세로 회전하면
/// 모델의 원점 좌표를 주어진 지리 좌표에 두고 모델의 XY 평면이 그 점의 접평면이 되게 하고 Z축이 지상 위로 향하도록 자세를 잡는다.
/// 모델 좌표축에 대한 회전각을 입력하면 주어진 지상점을 원점으로 하고 회전이 반영된 모델 자세를 구한다.
/// </summary>
/// <param name = "ptPos"> [In] 모델 원점 위치. </param>
/// <param name = "omega"> [In] 모델 좌표계 X축에 대한 회전각. </param>

/// </summary>
/// <param name = "yawPlatform"> [In] 기체 yaw 각도. </param>
/// <param name = "pitchPlatform"> [In] 기체 pitch 각도. </param>
/// <param name = "rollPlatform"> [In] 기체 roll 각도. </param>
/// <param name = "azimuthSensor"> [In] NED 기준 센서의 방위각. </param>
/// <param name = "elevSensor"> [In] NED 기준 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollSensor"> [In] 센서 렌즈 축의 회전각. </param>
/// <param name = "azimuthRelative"> [Out] 기체를 기준으로 한 센서의 방위각. </param>
/// <param name = "elevRelative"> [Out] 기체를 기준으로 한 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollRelative"> [Out] 센서 렌즈 축의 회전각. </param>
static void CalcRelativeSensorAttitudeInPlatformUAS(XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthSensor, XAngle^ elevSensor, XAngle^ rollSensor, [OutAttribute] XAngle^% azimuthRelative, [OutAttribute] XAngle^% elevRelative, [OutAttribute] XAngle^% rollRelative);

/// <summary>
/// 투영 좌표계 원점의 ENU 좌표계를 기준으로 하는 카메라 회전각 omega, phi, kappa에 해당하는 센서 위치의 yaw, pitch, roll을 계산한다.
/// </summary>
/// <param name = "ptOrigin"> [In] 투영 좌표계 원점 위치. (예. Korea TM Center 127,38 / East 129,38 / West 125,38 / UTM-k 127.5,38) </param>
