	NXImageView::NXImageView(void)
	{
		m_pImageView = nullptr;
		m_bUnderMouse = false;
		m_bLayerAdded = false;
		if(!Xfn::DesignMode)
		{
			if(m_ImageEngine == nullptr)
			{
				m_ImageEngine = gcnew NXImageEngine();
				NXDL::Xfn::AddToGCArray(m_ImageEngine);
			}

			NXImageView^ me = this;
			if(!m_ImageEngine->AddImageView(me))
			{
				// Error
				return;
			}

			OnRenderInner = gcnew NXImageView_Event_Render(this, &NXImageView::OnRenderEvent);
			IntPtr unmanaged = Marshal::GetFunctionPointerForDelegate(OnRenderInner);
			m_pImageView->OnRenderEvent = (XImageView_CallBack_Render)(void*)unmanaged;

			/*OnRenderEndInner = gcnew NXImageView_Event_Render(this, &NXImageView::OnRenderEndEvent);
			unmanaged = Marshal::GetFunctionPointerForDelegate(OnRenderEndInner);
			m_pImageView->OnRenderEndEvent = (XImageView_CallBack_Render)(void*)unmanaged;*/
		}
		OnLayerResizeEvent = gcnew System::EventHandler(this,&NXImageView::OnLayerResize);
		OnLayerMoveEvent = gcnew System::EventHandler(this,&NXImageView::OnLayerMove);

		Layers = gcnew ArrayList();

		InitializeComponent();
		m_bParentHandleEventAdded = false;
		m_bEnableChevronMenu = false;
//		DoubleBuffered = true;
	}

