XVertex2d^ NXImageView::ScreenToWorld(XVertex2d^ vScreenPos)
{
	if(!m_pImageView)	return nullptr;
	XDL::XVertex2d val(vScreenPos->x,vScreenPos->y);
	if(!m_pImageView->ScreenToWorld(val.x,val.y))
		return nullptr;

	RefreshScreen();
	return gcnew XVertex2d(val.x,val.y);
}

XVertex2d^ NXImageView::WorldToScreen(XVertex2d^ vSpacePos)
{
	if(!m_pImageView)	return nullptr;
	XDL::XVertex2d val(vSpacePos->x,vSpacePos->y);
	if(!m_pImageView->WorldToScreen(val.x,val.y))
		return nullptr;

	RefreshScreen();
	return gcnew XVertex2d(val.x,val.y);
}

bool NXImageView::RefreshScreen()
{
	if(!m_pImageView)	return false;
	m_pImageView->Invalidate();
	return true;
}

