	XVertex3d^ NXImageViewDrawArgs::Vertex3d(XVertex3d^ v)
	{
		XImageViewDrawArgs* pNative = (XImageViewDrawArgs*)m_pNative.ToPointer();
		if(!pNative || !v)	return nullptr;
		XDL::XVertex3d vn = pNative->Vertex3d(v->x,v->y,v->z);
		return gcnew XVertex3d(vn.x,vn.y,vn.z);
	}

	XVertex3d^ NXImageViewDrawArgs::Vertex3d(double x, double y, double z)
	{
		XImageViewDrawArgs* pNative = (XImageViewDrawArgs*)m_pNative.ToPointer();
		if(!pNative)	return nullptr;
		XDL::XVertex3d vn = pNative->Vertex3d(x,y,z);
		return gcnew XVertex3d(vn.x,vn.y,vn.z);
	}

	XVertex2d^ NXImageViewDrawArgs::ScreenToWorld(XVertex2d^ vScreenPos)
	{
		XImageViewDrawArgs* pNative = (XImageViewDrawArgs*)m_pNative.ToPointer();
		if(!pNative || !vScreenPos)	return nullptr;
		XDL::XVertex2d vS(vScreenPos->x,vScreenPos->y);
		XDL::XVertex3d vW;
		if(!pNative->ScreenToWorld(vS,vW)) return nullptr;
		return gcnew XVertex2d(vW.x,vW.y);
	}

	XVertex2d^ NXImageViewDrawArgs::WorldToScreen(XVertex2d^ vWorldPos)
	{
		XImageViewDrawArgs* pNative = (XImageViewDrawArgs*)m_pNative.ToPointer();
		if(!pNative || !vWorldPos)	return nullptr;
		XDL::XVertex3d vW(vWorldPos->x,vWorldPos->y,0);
		XDL::XVertex2d vS;
		if(!pNative->WorldToScreen(vW,vS)) return nullptr;
		return gcnew XVertex2d(vS.x,vS.y);
	}

	void NXImageViewDrawArgs::Invalidate()
	{
		XImageViewDrawArgs* pNative = (XImageViewDrawArgs*)m_pNative.ToPointer();
		if(!pNative)	return;
		pNative->Invalidate();
	}

	bool NXImageViewDrawArgs::SendMessage(Message% msg)
	{
		XImageViewDrawArgs* pNative = (XImageViewDrawArgs*)m_pNative.ToPointer();
		if(!pNative)	return false;
		return pNative->Send_Message((HWND)(msg.HWnd.ToPointer()),(WPARAM)msg.Msg,msg.WParam.ToInt64(),(LPARAM)msg.LParam.ToInt64());
	}

