	void NXImageView::WndProc(Message% m)
	{
		if (DesignMode)
		{
			System::Windows::Forms::Panel::WndProc(m);
			return;
		}

		if (m.Msg == WM_ERASEBKGND)
		{
			RefreshScreen();
			return;
		}

		if (m_ImageEngine) m_ImageEngine->PreTranslateMessage(m);

		return System::Windows::Forms::Panel::WndProc(m);
	}

