            }
            nxImageLayerComposite1.LayerVisible = true;   // 영상레이어를 보이도록 속성을 변경

            if (!nxImageView1.SetBackgroundMap("C:\\Pixoneer\\XDL3.0\\Config\\XImageBase.xml"))
